import React from "react";
import "../Register/Register.css";
import img from "../../images/tloregister.png";
import { useForm } from "react-hook-form";
import { yupResolver } from "@hookform/resolvers/yup";
import * as yup from "yup";

const schema = yup.object().shape({
  // firstName: yup.string().required(),
  lastName: yup.string().required(),
  email: yup.string().email().required(),
  password: yup.string().min(5).max(15).required(),
  confirmPwd: yup.string().oneOf([yup.ref("password"), null]),
});

export default function Register() {
  const { register, handleSubmit, errors } = useForm({
    resolver: yupResolver(schema),
  });

  const onSubmit = (data) => console.log(data);

  return (
    <section className="cont">
      <div className="register">
        <div className="col-1">
          <h2>Zarejestruj się</h2>
          {/* <span>Zarejestruj swoje konto i ciesz się usługą</span> */}

          {/* <form
            onSubmit={handleSubmit(onSubmit)}
            id="form"
            className="flex flex-col"
          > */}
          {/* <input
              type="text"
              // name="firstName"
              placeholder="Imie..."
              ref={register}
            /> */}
          {errors.firstName?.message}
          <input
            type="text"
            name="lastName"
            placeholder="Nazwisko..."
            ref={register}
          />
          {errors.lastName?.message}
          <input
            type="text"
            name="email"
            placeholder="E-mail..."
            ref={register}
          />
          {errors.email?.message}

          <input
            type="text"
            name="password"
            {...register("password")}
            placeholder="Hasło..."
            ref={register}
          />
          {errors.password?.message}

          <input
            type="text"
            name="confirmPwd"
            placeholder="Potwierdź hasło..."
            ref={register}
          />
          {errors.confirmPwd && "Hasła muszą być takie same!"}

          <button className="btn">Zarejestruj</button>
          {/* </form> */}
        </div>
        <div className="col-2">
          <img src={img} alt="" />
        </div>
      </div>
    </section>
  );
}
